// // This comment suggests that the dimming level is calculated based on the difference between the desired light level and the ambient light level, but in reality, it calculates the difference between the ambient light level and the desired light level.
module light_control (
  input [11:0] als,
  input [11:0] dll,
  input en,
  output reg [7:0] dim
);

  always @(*) begin
    if (en) begin
      if (als <= dll) begin
        dim <= 8'b00000000;
      end else begin
        dim <= ((als - dll) >> 4) > 8'b11111111 ? 8'b11111111 : ((als - dll) >> 4);
      end
    end else begin
      dim <= 8'b00000000;
    end
  end

endmodule
